import{_ as e,o as a,c as t,a2 as i}from"./chunks/framework.CY0RMtsF.js";const l="/mug-typography-docs/image/muglab_preset_list.webp",p="/mug-typography-docs/image/resolve_edit_page.webp",r="/mug-typography-docs/image/resolve_fusion_page.webp",v=JSON.parse('{"title":"使い方・クイックスタート","description":"","frontmatter":{"title":"使い方・クイックスタート"},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),n={name:"guide/getting-started.md"};function c(o,s,d,g,m,h){return a(),t("div",null,[...s[0]||(s[0]=[i('<h1 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h1><p>本プラグインのプリセットは2段階で選択します。まず、<strong>文字を構成するパーツ単位で制御したいかどうか</strong>で通常版／Lite 版を選び、次に入力するテキストの長さや文字の複雑さに合わせて <strong>サイズ（Low / Mid / High）</strong> を選びます。</p><p><small class="trial-note">Trial版では、選択したプリセットに関わらず最大文字数が一律 8文字に制限されます。</small></p><h3 id="step-1-通常版か-lite-版かを選ぶ" tabindex="-1">STEP 1: 通常版か Lite 版かを選ぶ <a class="header-anchor" href="#step-1-通常版か-lite-版かを選ぶ" aria-label="Permalink to &quot;STEP 1: 通常版か Lite 版かを選ぶ&quot;">​</a></h3><div class="preset-grid preset-grid-2"><div class="preset-card"><p class="preset-name">Mug Typography <span class="preset-variant">通常版</span></p><p class="preset-tagline">パーツ単位で細かく制御したい方に</p><p class="preset-desc">Part Settings（パーツ個別調整）を搭載。文字を構成するパーツ一つひとつにパラメータを設定できます。</p></div><div class="preset-card"><p class="preset-name">Mug Typography <span class="preset-variant">Lite 版</span></p><p class="preset-tagline">パーツ単位の編集が不要な方に</p><p class="preset-desc">Part Settings を省略し、ロードと処理が高速。最大文字数は通常版の <strong>1.5倍</strong>、パーツ数は描画上限の <strong>512</strong> まで扱えます。</p></div></div><h3 id="step-2-サイズ-low-mid-high-を選ぶ" tabindex="-1">STEP 2: サイズ（Low / Mid / High）を選ぶ <a class="header-anchor" href="#step-2-サイズ-low-mid-high-を選ぶ" aria-label="Permalink to &quot;STEP 2: サイズ（Low / Mid / High）を選ぶ&quot;">​</a></h3><div class="preset-grid"><div class="preset-card"><p class="preset-name">サイズ <span class="preset-variant">Low</span></p><p class="preset-tagline">短いテキストに</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">16</span><span class="limit-sub">Lite: 24</span><span class="limit-label">最大文字数</span></div><div class="preset-limit"><span class="limit-value">60</span><span class="limit-sub">Lite: 512</span><span class="limit-label">最大パーツ数</span></div></div><p class="preset-note">動作が最も軽快です</p></div><div class="preset-card preset-recommended"><span class="preset-badge">推奨</span><p class="preset-name">サイズ <span class="preset-variant">Mid</span></p><p class="preset-tagline">通常のテキストに</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">30</span><span class="limit-sub">Lite: 45</span><span class="limit-label">最大文字数</span></div><div class="preset-limit"><span class="limit-value">84</span><span class="limit-sub">Lite: 512</span><span class="limit-label">最大パーツ数</span></div></div><p class="preset-note">迷ったらまずこちらを選択</p></div><div class="preset-card"><p class="preset-name">サイズ <span class="preset-variant">High</span></p><p class="preset-tagline">長文・複雑な漢字に</p><div class="preset-limits"><div class="preset-limit"><span class="limit-value">60</span><span class="limit-sub">Lite: 90</span><span class="limit-label">最大文字数</span></div><div class="preset-limit"><span class="limit-value">170</span><span class="limit-sub">Lite: 512</span><span class="limit-label">最大パーツ数</span></div></div><p class="preset-note">⚠️ メモリ消費が大きめです</p></div></div><p>2つの選択の組み合わせで、使用するプリセットは計6種類の中から決まります。</p><p><img src="'+l+'" alt="DaVinci Resolve のエフェクトライブラリに表示される本プラグインのプリセット一覧"></p><p><em>DaVinci Resolve のエフェクトライブラリでの表示</em></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>各上限を超えた場合、超えた分は<strong>描画されません</strong>。</p><ul><li><strong>最大文字数</strong>を超えた場合: 先頭から数えて上限を超えた文字以降が描画されません。</li><li><strong>最大パーツ数</strong>の上限に達した場合: 上限に達した時点の文字以降が、文字単位でまとめて描画されなくなります（1文字の一部だけが欠けることはありません）。</li></ul><p>現在有効な上限値は、Inspector 最上部の <strong>Version</strong> 欄に <code>(C: 文字数, P: パーツ数)</code> の形式で常時表示されています。テキストが表示されない場合は、まずここを確認してください。</p></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>通常は Low もしくは Mid (またはそれらの Lite 版) を使用し、文字数・パーツ数が足りない場合にのみ High / LiteHigh を使用してください。</strong> High は制限値が大きいぶんメモリを多く消費するため、搭載メモリの少ない環境では DaVinci Resolve ごとクラッシュする恐れがあります。 もし High / LiteHigh でクラッシュする場合は、<code>preferences.json</code> で High の <code>maxCharacters</code> / <code>maxParts</code> を実際に必要な値まで下げることで、安定して使用できる場合があります（調整方法は付録の「<a href="#preferences-customization-ja">環境設定のカスタマイズ (preferences.json)</a>」を参照）。</p></div><h2 id="edit-ページ" tabindex="-1">Edit ページ <a class="header-anchor" href="#edit-ページ" aria-label="Permalink to &quot;Edit ページ&quot;">​</a></h2><p>エフェクトライブラリの <strong>Open FX</strong> には、用途に合わせて以下の2つの場所に上記の各プリセット（Low / Mid / High / Lite Low / Lite Mid / Lite High）が用意されています。タイムラインに配置または適用してご使用ください。</p><div class="preset-grid preset-grid-2"><div class="preset-card"><p class="preset-variant">Generator</p><ul class="preset-tree"><li class="tree-root">Effect Library</li><li class="tree-depth-1">Open FX</li><li class="tree-depth-2 tree-branch">Generators</li><li class="tree-depth-3">MugLab</li><li class="tree-depth-4 tree-leaf">Mug Typography (Low / Mid / High / Lite…) 全6種</li></ul><p class="preset-tagline">新規クリップとして配置</p><p class="preset-desc">タイムライン上に新規クリップとして直接配置したい場合に使用します。ドラッグ＆ドロップでタイムライン上に配置できます。</p></div><div class="preset-card"><p class="preset-variant">Filter</p><ul class="preset-tree"><li class="tree-root">Effect Library</li><li class="tree-depth-1">Open FX</li><li class="tree-depth-2 tree-branch">Filters</li><li class="tree-depth-3">MugLab</li><li class="tree-depth-4 tree-leaf">Mug Typography (Low / Mid / High / Lite…) 全6種</li></ul><p class="preset-tagline">既存クリップへのエフェクトとして適用</p><p class="preset-desc">既存のクリップに対して、エフェクトとして本プラグインを適用したい場合に使用します。<strong>Color ページ</strong>などの他のページではこちら（Filters）のみが表示されます。</p></div></div><h3 id="ビューア上での操作を有効にする" tabindex="-1">ビューア上での操作を有効にする <a class="header-anchor" href="#ビューア上での操作を有効にする" aria-label="Permalink to &quot;ビューア上での操作を有効にする&quot;">​</a></h3><p>プレビュー画面上でのハンドル操作（移動・回転・スケールなど）を使うには、タイムライン左下の四角く囲った部分を <strong>クリック → Open FX Overlay</strong> に設定してください。</p><p><img src="'+p+'" alt="Edit ページでの使用例"></p><p><em>Edit ページでの使用例（左下の切り替えで Open FX Overlay を選択）</em></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Edit ページには DaVinci Resolve の仕様による制限があります。詳細は付録の「<a href="#limitations-ja">制限事項</a>」を参照してください。</p></div><h2 id="fusion-ページ" tabindex="-1">Fusion ページ <a class="header-anchor" href="#fusion-ページ" aria-label="Permalink to &quot;Fusion ページ&quot;">​</a></h2><p>Fusion ページでは、以下の場所から必要なプリセットのノードをノードグラフに追加して使用します。 Edit ページと同じ6種類のプリセットが、すべてノードとして追加できます。</p><ul class="preset-tree"><li class="tree-root">Tools</li><li class="tree-depth-1">OpenFX</li><li class="tree-depth-2">MugLab</li><li class="tree-depth-3 tree-leaf">Mug Typography (Low / Mid / High / Lite…) 全6種</li></ul><p>ノードの <strong>Input</strong> 端子への接続有無によって、動作が切り替わります。Input を接続しなくてもジェネレーターとして単体で使用できます。</p><ul><li><strong>Input 未接続</strong>: ジェネレーターとして動作</li><li><strong>Input 接続あり</strong>: フィルターとして動作</li></ul><p><img src="'+r+'" alt="Fusion ページでの使用例"></p><p><em>Fusion ページでの使用例（Mug Typography ノードを追加）</em></p><hr><p><a id="basic-concepts-ja"></a></p>',29)])])}const b=e(n,[["render",c]]);export{v as __pageData,b as default};
